Real64 SandiaModuleTemperature(Real64 const Ibc, // beam radiation on collector plane, W/m2
                                   Real64 const Idc, // Diffuse radiation on collector plane, W/m2
                                   Real64 const Ws,  // wind speed, m/s
                                   Real64 const Ta,  // ambient temperature, degC
                                   Real64 const fd,  // fraction of Idc used (empirical constant)
                                   Real64 const a,   // empirical constant
                                   Real64 const b    // empirical constant
    )
    {
        // FUNCTION INFORMATION:
        //       AUTHOR         G. Barker
        //       DATE WRITTEN   unknown
        //       MODIFIED       na
        //       RE-ENGINEERED  B.Griffith December 2003

        // PURPOSE OF THIS FUNCTION:
        // Returns back-of-module temperature, deg C

        // METHODOLOGY EMPLOYED:
        // apply sandia temperature model, This is module temp or back of
        // of the panel.  A separate correction handles delta T for actual cell

        // REFERENCES:
        // from G. Barker's TRNSYS implementation
        // Equations (10)  in Davis, M.W., A.H. Fanney, B.P. Dougherty. Measured versus
        //   predicted performance of building integrated photovoltaics,
        //   Solar 2002, Sunrise on the Reliable Energy Economy,
        //   June 15-19, 2002, Reno, NV.

        // Return value
        Real64 SandiaModuleTemperature;

        Real64 E; // total irradiance working variable

        E = Ibc + fd * Idc;

        SandiaModuleTemperature = E * std::exp(a + b * Ws) + Ta;

        return SandiaModuleTemperature;
    }

Real64 PsyRhoAirFnPbTdbW(Real64 const pb,  // barometric pressure (Pascals)
                                       Real64 const tdb, // dry bulb temperature (Celsius)
                                       Real64 const dw   // humidity ratio (kgWater/kgDryAir)
    )
    {
        // FUNCTION INFORMATION:
        //       AUTHOR         G. S. Wright
        //       DATE WRITTEN   June 2, 1994
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // This function provides density of air as a function of barometric
        // pressure, dry bulb temperature, and humidity ratio.

        // METHODOLOGY EMPLOYED:
        // ideal gas law
        //    universal gas const for air 287 J/(kg K)
        //    air/water molecular mass ratio 28.9645/18.01534

        // REFERENCES:
        // Wylan & Sontag, Fundamentals of Classical Thermodynamics.
        // ASHRAE handbook 1985 Fundamentals, Ch. 6, eqn. (6),(26)

        return (pb / (287.0 * (tdb + Constant::Kelvin) * (1.0 + 1.6077687 * std::max(dw, 1.0e-5))));
    }

Real64 PsyTdbFnHW(Real64 const H, // enthalpy {J/kg}
                             Real64 const dW // humidity ratio
    )
    {
        // FUNCTION INFORMATION:
        //       AUTHOR         J. C. VanderZee
        //       DATE WRITTEN   Feb. 1994
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // This function provides air temperature from enthalpy and humidity ratio.

        // REFERENCES:
        // ASHRAE HANDBOOK OF FUNDAMENTALS, 1972, P100, EQN 32
        //   by inverting function PsyHFnTdbW

        Real64 const W(max(dW, 1.0e-5));                          // humidity ratio
        return (H - 2.50094e6 * W) / (1.00484e3 + 1.85895e3 * W); // result=> dry-bulb temperature {C}
    }

