Real64 CalcWindSurfaceTheta(Real64 const WindDir, Real64 const SurfAzimuth)
{
    // Computes the angle theta between the wind direction and the surface azimuth
    // Should always be a value between 0-180 deg

    Real64 windDir = std::fmod(WindDir, 360);
    Real64 surfAzi = std::fmod(SurfAzimuth, 360);
    Real64 theta = std::abs(windDir - surfAzi);
    if (theta > 180) {
        return abs(theta - 360);
    }
    return theta;
}

mojo_source:
def CalcWindSurfaceTheta(WindDir: Float64, SurfAzimuth: Float64) -> Float64:
    var windDir: Float64 = WindDir - 360.0 * Float64(Int(WindDir / 360.0))
    var surfAzi: Float64 = SurfAzimuth - 360.0 * Float64(Int(SurfAzimuth / 360.0))
    var theta: Float64 = abs(windDir - surfAzi)
    if theta > 180.0:
        return Float64(abs(Int(theta - 360.0)))
    return theta

