void NormalizePhiTheta(Real64 &phi, Real64 &theta)
{

    while (phi > 2 * Constant::Pi) {
        phi -= 2 * Constant::Pi;
    }
    if (phi > Constant::Pi) {
        phi = 2 * Constant::Pi - phi;
    }

    while (theta > 2 * Constant::Pi) {
        theta -= 2 * Constant::Pi;
    }
    if (theta > Constant::Pi) {
        theta = 2 * Constant::Pi - theta;
    }
}

mojo_source:
def NormalizePhiTheta(mut phi: Float64, mut theta: Float64):
    var pi: Float64 = 3.14159265358979324
    while phi > 2.0 * pi:
        phi -= 2.0 * pi
    if phi > pi:
        phi = 2.0 * pi - phi
    while theta > 2.0 * pi:
        theta -= 2.0 * pi
    if theta > pi:
        theta = 2.0 * pi - theta

